  // otherwise, we must compare with the maximum and replace if needed
  unsigned maximum = 0;
  bool had_max = max_heap_maximum(finder->heap, &maximum);
  assert(had_max);
  assert(maximum < finder->size);
  if (entry.cost <= finder->entries[maximum].cost) {
