        while idx > 0 {
            let parent = (idx - 1) / 2;
            if (self.comparator)(self.data[idx], self.data[parent]) > 0 {
                self.data.swap(idx, parent);
                idx = parent;
            } else {
                break;
            }
        }
    }

    fn heapify_down(&mut self, mut idx: usize) {
        loop {
            let left = 2 * idx + 1;
            let right = 2 * idx + 2;
            let mut largest = idx;

            if left < self.data.len() && (self.comparator)(self.data[left], self.data[largest]) > 0 {
                largest = left;
            }

            if right < self.data.len() && (self.comparator)(self.data[right], self.data[largest]) > 0 {
                largest = right;
            }

            if largest != idx {
                self.data.swap(idx, largest);
                idx = largest;
            } else {
                break;
            }
        }
    }

    pub fn insert(&mut self, value: u32) -> bool {
        if self.data.len() >= self.capacity {
            return false;
        }

        self.data.push(value);
        self.heapify_up(self.data.len() - 1);
